"""JWT authentication utilities."""
import jwt
import time

SECRET = 'change-in-production'
ALGORITHM = 'HS256'

def create_token(user_id: str, expires_in: int = 3600) -> str:
    payload = {'sub': user_id, 'exp': time.time() + expires_in}
    return jwt.encode(payload, SECRET, algorithm=ALGORITHM)

def verify_token(token: str) -> dict | None:
    try:
        return jwt.decode(token, SECRET, algorithms=[ALGORITHM])
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None

"""Authentication route handlers."""
from flask import Blueprint, request, jsonify
from .jwt import create_token, verify_token
from .models import User

auth_bp = Blueprint('auth', __name__, url_prefix='/auth')

@auth_bp.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    user = User.query.filter_by(email=data.get('email')).first()
    if user and user.check_password(data.get('password')):
        token = create_token(str(user.id))
        return jsonify({'token': token, 'expires_in': 3600})
    return jsonify({'error': 'Invalid credentials'}), 401

@auth_bp.route('/logout', methods=['POST'])
def logout():
    # Token invalidation handled client-side
    return jsonify({'message': 'Logged out successfully'})
